module top_module (
    input clk,
    input reset,
    output [1:0] gray_count );reg [1:0] invalid_gray;
    reg [1:0] gray_count_reg;

    always @(posedge clk) begin
        if (reset)
            invalid_gray <= 2'b00;
        else
            invalid_gray <= invalid_gray + 1;
    end

    always @(*) begin
        gray_count_reg = {invalid_gray[1], invalid_gray[1] ^ invalid_gray[0]};
    end

    assign gray_count = gray_count_reg;

endmodule
